const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const exec = d.executive_summary || {};
const projects = (d.projects || []).map(p => `## ${p.health} ${p.name}
- Variance: ${p.schedule_variance_days}d | Risks: ${p.open_risks} | Budget: ${p.budget_health}`).join('

');
const missions = (d.missions?.upcoming || []).slice(0, 5).map((m, i) => `${i+1}. [${m.priority}] ${m.title} → ${m.assigned_to}`).join('
') || 'None queued';
const connectors = (d.connectors || []).map(c => `- ${c.connector}: ${c.errors > 0 ? c.errors + ' errors' : 'OK'}`).join('
') || 'None';

const md = `# HCI AI — Weekly Sprint Review
**${d.period || today}**

## Executive Summary
- Hours saved this week: ${exec.hours_saved_this_week || 0}h
- Documents processed: ${exec.documents_processed || 0}
- Risks detected: ${exec.risks_detected || 0}
- Workflow runs: ${exec.workflow_runs || 0}

## Projects
${projects || 'No project data'}

## Top Missions (Next 5)
${missions}

## Connector Health
${connectors}

---
*Generated: ${new Date().toISOString()} by AUTO-010*`;

return [{ json: { filename: `reports/sprint/weekly-${today}.md`, content: md, date: today } }];
